1	package fec
2	
3	import (
4		"bytes"
5		"math/rand"
6		"testing"
7	
8		"github.com/klauspost/reedsolomon"
9	)
10	
11	// emitGroup codes payloads into ONE group at parity target k and returns its data
12	// shards plus the parity emitted at close. It admits every payload (each emits a data
13	// shard) and, when the group did not fill to DataShards, flushes it so a PARTIAL
14	// group (m < DataShards) still closes and carries its parity — the deadline-flushed
15	// case the adaptive datapath actually produces. len(payloads) is the group
16	// cardinality m; it must be in [1, cfg.DataShards].
17	func emitGroup(t *testing.T, cfg Config, k int, payloads [][]byte) ([]DataShard, []ParityShard) {
18		t.Helper()
19		if len(payloads) < 1 || len(payloads) > cfg.DataShards {
20			t.Fatalf("emitGroup: m=%d out of [1,%d]", len(payloads), cfg.DataShards)
21		}
22		enc, err := NewEncoder(cfg, newFakeClock())
23		if err != nil {
24			t.Fatal(err)
25		}
26		enc.SetParity(k)
27		var data []DataShard
28		var parity []ParityShard
29		for i, p := range payloads {
30			ds, par, err := enc.Admit(p)
31			if err != nil {
32				t.Fatalf("admit %d: %v", i, err)
33			}
34			data = append(data, ds)
35			if par != nil {
36				parity = par
37			}
38		}
39		// A partial group (m < DataShards) is still open; flush it so its parity is coded
40		// over the m shards admitted so far, exactly as the deadline path would.
41		if _, open := enc.NextDeadline(); open {
42			par, err := enc.Flush()
43			if err != nil {
44				t.Fatalf("flush partial group (m=%d k=%d): %v", len(payloads), k, err)
45			}
46			parity = par
47		}
48		return data, parity
49	}
50	
51	// TestPartialGroupByteExactAtCeiling is the D25 partial-group property test: it
52	// round-trips the FULL (partial-m x partial-k) space the adaptive encoder actually
53	// produces — every m in [1,DataShards] crossed with every k in [0,ceiling] — through a
54	// SINGLE decoder built at the fixed ceiling parity, asserting BYTE-EXACT recovery of
55	// every payload. The pre-existing TestVaryingParityDecodesAtCeiling only covered full
56	// groups (m == DataShards); a deadline-flushed group with m < DataShards AND
57	// k < ceiling simultaneously was never round-tripped.
58	//
59	// This is a genuine witness of the klauspost prefix-stability the datapath rests on:
60	// the encoder codes each group RS(m, k) while the decoder reconstructs against
61	// RS(m, ceiling). Recovery is byte-exact ONLY IF parity shard j is identical for
62	// RS(m, k) and RS(m, ceiling). Were a future reedsolomon default to break that (Cauchy/
63	// PAR1/Jerasure/leopard, or a k==1 XOR fast path), the decoder would reconstruct WRONG
64	// bytes from the mismatched parity and this test's byte-exact assertion would fail.
65	func TestPartialGroupByteExactAtCeiling(t *testing.T) {
66		const (
67			ceiling = 6
68			N       = 10
69		)
70		cfg := Config{DataShards: N, ParityShards: ceiling, Deadline: testDeadline}
71		rng := rand.New(rand.NewSource(20260708))
72	
73		for m := 1; m <= N; m++ {
74			for k := 0; k <= ceiling; k++ {
75				originals := randomPayloads(rng, m)
76				data, parity := emitGroup(t, cfg, k, originals)
77				if len(data) != m {
78					t.Fatalf("m=%d k=%d: emitted %d data shards, want %d", m, k, len(data), m)
79				}
80				if len(parity) != k {
81					t.Fatalf("m=%d k=%d: emitted %d parity, want %d", m, k, len(parity), k)
82				}
83	
84				// ONE decoder built at the fixed ceiling — exactly as the bind builds it once
85				// per Open and feeds every varying-M group through it.
86				dec, err := NewDecoder(cfg)
87				if err != nil {
88					t.Fatal(err)
89				}
90	
91				// Drop the maximal recoverable number of data shards: min(k, m). Survivors
92				// (m-drop) data + k parity >= m iff k >= drop, which holds. k == 0 drops
93				// nothing (no protection): every data frame must simply arrive intact.
94				drop := k
95				if drop > m {
96					drop = m
97				}
98				perm := rng.Perm(m)
99				dropped := make(map[int]bool, drop)
100				for i := 0; i < drop; i++ {
101					dropped[perm[i]] = true
102				}
103	
104				got := make(map[int][]byte)
105				survivors := make([]Shard, 0, m+k)
106				for i := 0; i < m; i++ {
107					if dropped[i] {
108						continue
109					}
110					survivors = append(survivors, data[i])
111					got[i] = data[i].Payload
112				}
113				for _, p := range parity {
114					survivors = append(survivors, p)
115				}
116				// Shuffle arrival order so data-before-parity and parity-before-data are both
117				// exercised across the (m,k) grid.
118				rng.Shuffle(len(survivors), func(a, b int) { survivors[a], survivors[b] = survivors[b], survivors[a] })
119				for _, s := range survivors {
120					rec, err := dec.Offer(s)
121					if err != nil {
122						t.Fatalf("m=%d k=%d: offer %#v: %v", m, k, s, err)
123					}
124					for _, r := range rec {
125						got[r.Index] = r.Payload
126					}
127				}
128	
129				if len(got) != m {
130					t.Fatalf("m=%d k=%d (dropped %d data): recovered %d of %d frames", m, k, drop, len(got), m)
131				}
132				for i, want := range originals {
133					if !bytes.Equal(got[i], want) {
134						t.Fatalf("m=%d k=%d frame %d NOT byte-exact:\n want %x\n got  %x", m, k, i, want, got[i])
135					}
136				}
137			}
138		}
139	}
140	
141	// encodeParityDefault codes m data shards into k parity shards through the EXACT call
142	// the FEC codec uses — reedsolomon.New(m, k) with the default options — and returns
143	// the k parity shard payloads. It is the primitive the prefix-stability invariant
144	// pins.
145	func encodeParityDefault(t *testing.T, m, k int, data [][]byte) [][]byte {
146		t.Helper()
147		c, err := reedsolomon.New(m, k)
148		if err != nil {
149			t.Fatalf("reedsolomon.New(%d,%d): %v", m, k, err)
150		}
151		shardLen := len(data[0])
152		shards := make([][]byte, m+k)
153		for i := 0; i < m; i++ {
154			shards[i] = append([]byte(nil), data[i]...)
155		}
156		for j := 0; j < k; j++ {
157			shards[m+j] = make([]byte, shardLen)
158		}
159		if err := c.Encode(shards); err != nil {
160			t.Fatalf("encode RS(%d,%d): %v", m, k, err)
161		}
162		out := make([][]byte, k)
163		for j := 0; j < k; j++ {
164			out[j] = shards[m+j]
165		}
166		return out
167	}
168	
169	// TestKlauspostParityPrefixStableInvariant is the D25 build/test-time invariant that
170	// PINS the undocumented reedsolomon guarantee the fixed-ceiling FEC decoder silently
171	// relies on: for a fixed data-shard count m, the generator-matrix parity rows form a
172	// STABLE PREFIX as the total parity count varies. Operationally, parity shard j coded
173	// by RS(m, k) is byte-identical to parity shard j coded by RS(m, ceiling) for every
174	// j < k. This is why a group the encoder codes RS(m, k<ceiling) decodes unchanged
175	// against the decoder's RS(m, ceiling) codec.
176	//
177	// reedsolomon.New's DEFAULT matrix (v1.14.1) is buildMatrix = Vandermonde x top-inverse:
178	// parity row (m+j) is vandermonde row (m+j) multiplied by the inverse of the top mxm
179	// square, and BOTH factors depend only on (m, j) — never on the total shard count — so
180	// the prefix is stable. This test fails LOUDLY if a reedsolomon upgrade flips that
181	// default (Cauchy/PAR1/Jerasure/leopard, or a k==1 XOR fast path), which would otherwise
182	// SILENTLY corrupt every reconstructed inner datagram with no other test catching it.
183	// See the go.mod pin note next to github.com/klauspost/reedsolomon.
184	func TestKlauspostParityPrefixStableInvariant(t *testing.T) {
185		const (
186			ceiling  = 8
187			maxData  = 20
188			shardLen = 64
189		)
190		rng := rand.New(rand.NewSource(0x0FEC))
191		for m := 1; m <= maxData; m++ {
192			data := make([][]byte, m)
193			for i := range data {
194				data[i] = make([]byte, shardLen)
195				rng.Read(data[i])
196			}
197			ref := encodeParityDefault(t, m, ceiling, data) // RS(m, ceiling) reference
198			for k := 1; k <= ceiling; k++ {
199				got := encodeParityDefault(t, m, k, data)
200				for j := 0; j < k; j++ {
201					if !bytes.Equal(got[j], ref[j]) {
202						t.Fatalf("reedsolomon parity-prefix stability VIOLATED: RS(%d,%d) parity[%d] != RS(%d,%d) parity[%d].\n"+
203							"The fixed-ceiling FEC decoder reconstructs varying-M groups against RS(m,ceiling) and would now SILENTLY corrupt every recovered payload.\n"+
204							"A reedsolomon upgrade likely changed the default New() matrix away from Vandermonde x top-inverse; re-verify and re-pin (see go.mod note).",
205							m, k, j, m, ceiling, j)
206					}
207				}
208			}
209		}
210	}
