package fec

import (
	"bytes"
	"math/rand"
	"testing"

	"github.com/klauspost/reedsolomon"
)

// emitGroup codes payloads into ONE group at parity target k and returns its data
// shards plus the parity emitted at close. It admits every payload (each emits a data
// shard) and, when the group did not fill to DataShards, flushes it so a PARTIAL
// group (m < DataShards) still closes and carries its parity — the deadline-flushed
// case the adaptive datapath actually produces. len(payloads) is the group
// cardinality m; it must be in [1, cfg.DataShards].
func emitGroup(t *testing.T, cfg Config, k int, payloads [][]byte) ([]DataShard, []ParityShard) {
	t.Helper()
	if len(payloads) < 1 || len(payloads) > cfg.DataShards {
		t.Fatalf("emitGroup: m=%d out of [1,%d]", len(payloads), cfg.DataShards)
	}
	enc, err := NewEncoder(cfg, newFakeClock())
	if err != nil {
		t.Fatal(err)
	}
	enc.SetParity(k)
	var data []DataShard
	var parity []ParityShard
	for i, p := range payloads {
		ds, par, err := enc.Admit(p)
		if err != nil {
			t.Fatalf("admit %d: %v", i, err)
		}
		data = append(data, ds)
		if par != nil {
			parity = par
		}
	}
	// A partial group (m < DataShards) is still open; flush it so its parity is coded
	// over the m shards admitted so far, exactly as the deadline path would.
	if _, open := enc.NextDeadline(); open {
		par, err := enc.Flush()
		if err != nil {
			t.Fatalf("flush partial group (m=%d k=%d): %v", len(payloads), k, err)
		}
		parity = par
	}
	return data, parity
}

// TestPartialGroupByteExactAtCeiling is the D25 partial-group property test: it
// round-trips the FULL (partial-m x partial-k) space the adaptive encoder actually
// produces — every m in [1,DataShards] crossed with every k in [0,ceiling] — through a
// SINGLE decoder built at the fixed ceiling parity, asserting BYTE-EXACT recovery of
// every payload. The pre-existing TestVaryingParityDecodesAtCeiling only covered full
// groups (m == DataShards); a deadline-flushed group with m < DataShards AND
// k < ceiling simultaneously was never round-tripped.
//
// This is a genuine witness of the klauspost prefix-stability the datapath rests on:
// the encoder codes each group RS(m, k) while the decoder reconstructs against
// RS(m, ceiling). Recovery is byte-exact ONLY IF parity shard j is identical for
// RS(m, k) and RS(m, ceiling). Were a future reedsolomon default to break that (Cauchy/
// PAR1/Jerasure/leopard, or a k==1 XOR fast path), the decoder would reconstruct WRONG
// bytes from the mismatched parity and this test's byte-exact assertion would fail.
func TestPartialGroupByteExactAtCeiling(t *testing.T) {
	const (
		ceiling = 6
		N       = 10
	)
	cfg := Config{DataShards: N, ParityShards: ceiling, Deadline: testDeadline}
	rng := rand.New(rand.NewSource(20260708))

	for m := 1; m <= N; m++ {
		for k := 0; k <= ceiling; k++ {
			originals := randomPayloads(rng, m)
			data, parity := emitGroup(t, cfg, k, originals)
			if len(data) != m {
				t.Fatalf("m=%d k=%d: emitted %d data shards, want %d", m, k, len(data), m)
			}
			if len(parity) != k {
				t.Fatalf("m=%d k=%d: emitted %d parity, want %d", m, k, len(parity), k)
			}

			// ONE decoder built at the fixed ceiling — exactly as the bind builds it once
			// per Open and feeds every varying-M group through it.
			dec, err := NewDecoder(cfg)
			if err != nil {
				t.Fatal(err)
			}

			// Drop the maximal recoverable number of data shards: min(k, m). Survivors
			// (m-drop) data + k parity >= m iff k >= drop, which holds. k == 0 drops
			// nothing (no protection): every data frame must simply arrive intact.
			drop := k
			if drop > m {
				drop = m
			}
			perm := rng.Perm(m)
			dropped := make(map[int]bool, drop)
			for i := 0; i < drop; i++ {
				dropped[perm[i]] = true
			}

			got := make(map[int][]byte)
			survivors := make([]Shard, 0, m+k)
			for i := 0; i < m; i++ {
				if dropped[i] {
					continue
				}
				survivors = append(survivors, data[i])
				got[i] = data[i].Payload
			}
			for _, p := range parity {
				survivors = append(survivors, p)
			}
			// Shuffle arrival order so data-before-parity and parity-before-data are both
			// exercised across the (m,k) grid.
			rng.Shuffle(len(survivors), func(a, b int) { survivors[a], survivors[b] = survivors[b], survivors[a] })
			for _, s := range survivors {
				rec, err := dec.Offer(s)
				if err != nil {
					t.Fatalf("m=%d k=%d: offer %#v: %v", m, k, s, err)
				}
				for _, r := range rec {
					got[r.Index] = r.Payload
				}
			}

			if len(got) != m {
				t.Fatalf("m=%d k=%d (dropped %d data): recovered %d of %d frames", m, k, drop, len(got), m)
			}
			for i, want := range originals {
				if !bytes.Equal(got[i], want) {
					t.Fatalf("m=%d k=%d frame %d NOT byte-exact:\n want %x\n got  %x", m, k, i, want, got[i])
				}
			}
		}
	}
}

// encodeParityDefault codes m data shards into k parity shards through the EXACT call
// the FEC codec uses — reedsolomon.New(m, k) with the default options — and returns
// the k parity shard payloads. It is the primitive the prefix-stability invariant
// pins.
func encodeParityDefault(t *testing.T, m, k int, data [][]byte) [][]byte {
	t.Helper()
	c, err := reedsolomon.New(m, k)
	if err != nil {
		t.Fatalf("reedsolomon.New(%d,%d): %v", m, k, err)
	}
	shardLen := len(data[0])
	shards := make([][]byte, m+k)
	for i := 0; i < m; i++ {
		shards[i] = append([]byte(nil), data[i]...)
	}
	for j := 0; j < k; j++ {
		shards[m+j] = make([]byte, shardLen)
	}
	if err := c.Encode(shards); err != nil {
		t.Fatalf("encode RS(%d,%d): %v", m, k, err)
	}
	out := make([][]byte, k)
	for j := 0; j < k; j++ {
		out[j] = shards[m+j]
	}
	return out
}

// TestKlauspostParityPrefixStableInvariant is the D25 build/test-time invariant that
// PINS the undocumented reedsolomon guarantee the fixed-ceiling FEC decoder silently
// relies on: for a fixed data-shard count m, the generator-matrix parity rows form a
// STABLE PREFIX as the total parity count varies. Operationally, parity shard j coded
// by RS(m, k) is byte-identical to parity shard j coded by RS(m, ceiling) for every
// j < k. This is why a group the encoder codes RS(m, k<ceiling) decodes unchanged
// against the decoder's RS(m, ceiling) codec.
//
// reedsolomon.New's DEFAULT matrix (v1.14.1) is buildMatrix = Vandermonde x top-inverse:
// parity row (m+j) is vandermonde row (m+j) multiplied by the inverse of the top mxm
// square, and BOTH factors depend only on (m, j) — never on the total shard count — so
// the prefix is stable. This test fails LOUDLY if a reedsolomon upgrade flips that
// default (Cauchy/PAR1/Jerasure/leopard, or a k==1 XOR fast path), which would otherwise
// SILENTLY corrupt every reconstructed inner datagram with no other test catching it.
// See the go.mod pin note next to github.com/klauspost/reedsolomon.
func TestKlauspostParityPrefixStableInvariant(t *testing.T) {
	const (
		ceiling  = 8
		maxData  = 20
		shardLen = 64
	)
	rng := rand.New(rand.NewSource(0x0FEC))
	for m := 1; m <= maxData; m++ {
		data := make([][]byte, m)
		for i := range data {
			data[i] = make([]byte, shardLen)
			rng.Read(data[i])
		}
		ref := encodeParityDefault(t, m, ceiling, data) // RS(m, ceiling) reference
		for k := 1; k <= ceiling; k++ {
			got := encodeParityDefault(t, m, k, data)
			for j := 0; j < k; j++ {
				if !bytes.Equal(got[j], ref[j]) {
					t.Fatalf("reedsolomon parity-prefix stability VIOLATED: RS(%d,%d) parity[%d] != RS(%d,%d) parity[%d].\n"+
						"The fixed-ceiling FEC decoder reconstructs varying-M groups against RS(m,ceiling) and would now SILENTLY corrupt every recovered payload.\n"+
						"A reedsolomon upgrade likely changed the default New() matrix away from Vandermonde x top-inverse; re-verify and re-pin (see go.mod note).",
						m, k, j, m, ceiling, j)
				}
			}
		}
	}
}

package bind

import (
	"bytes"
	"io"
	"net/netip"
	"sync"
	"testing"
	"time"

	"github.com/7mind/wanbond/internal/config"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/frame"
	"github.com/7mind/wanbond/internal/log"
	"github.com/7mind/wanbond/internal/sched"
	"github.com/7mind/wanbond/internal/telemetry"
)

// newProbingMultipathFEC is newProbingMultipath with a FEC config threaded through NewMultipath,
// so a concentrator peer bound lazily over its sockets re-instantiates its FULL heavy trio
// (resequencer + FEC DECODE and FEC ENCODE planes) on binding — the FEC-on lifecycle the T91
// FEC-off fixtures could not exercise (every prior fixture passed nil fecCfg, making the
// 'fecRecv nil / fecSend nil' assertions vacuous).
func newProbingMultipathFEC(t testing.TB, paths []config.Path, psk config.Key, fecCfg *fec.Config, clk telemetry.Clock) (*Multipath, []*telemetry.Prober) {
	t.Helper()
	lg, err := log.New("error", io.Discard)
	if err != nil {
		t.Fatalf("build logger: %v", err)
	}
	cfg := telemetry.ProberConfig{
		LossWindow: 0,
		Liveness:   telemetry.LivenessConfig{DownAfter: testProbeDownAfter, UpAfterSuccesses: testProbeUpSucc},
	}
	newProber := func(name string, id uint8) *telemetry.Prober {
		return telemetry.NewProber(name, id, testProbeSessionID, psk, cfg, clk, lg)
	}
	probers := make([]*telemetry.Prober, len(paths))
	health := make([]sched.PathHealth, len(paths))
	for i := range paths {
		probers[i] = newProber(paths[i].Name, uint8(i))
		health[i] = probers[i]
	}
	scheduler, err := sched.NewActiveBackup(health, sched.Config{FailbackAfter: time.Hour}, clk, lg)
	if err != nil {
		t.Fatalf("build scheduler: %v", err)
	}
	m, err := NewMultipath(paths, psk, scheduler, probers, newProber, fecCfg, nil, config.Amnezia{})
	if err != nil {
		t.Fatalf("NewMultipath: %v", err)
	}
	return m, probers
}

// lazyConcentratorFEC is lazyConcentrator with FEC configured: a one-shared-socket Multipath
// whose primary is keyed by pskA and whose SECOND peer (pskB) is bound LAZILY (no heavy state
// yet). Because fecCfg is non-nil, ensurePeerReceiveInstantiated builds the peer's FEC decode
// AND encode planes on binding (and teardownPeerLocked frees them), so the FEC-plane lifecycle
// asserted below is driven by PRODUCTION code, not the fixture.
func lazyConcentratorFEC(t *testing.T, pskA, pskB config.Key, fecCfg *fec.Config) (m *Multipath, primary, second *peerState, clk *fakeClock) {
	t.Helper()
	clk = newFakeClock()
	m, _ = newProbingMultipathFEC(t, loopbackPaths(1), pskA, fecCfg, clk)
	if _, _, err := m.Open(0); err != nil {
		t.Fatalf("Open: %v", err)
	}
	t.Cleanup(func() { _ = m.Close() })
	primary = m.peerState
	second = bindLazyPeer(t, m, "peer-b", pskB, clk)
	if peerPathByName(second, "a") == nil {
		t.Fatalf("second peer has no view of shared path 'a': %v", pathNamesOfPeer(second))
	}
	return m, primary, second, clk
}

// offerReconstructingParity delivers, through the demux, a GENUINE single-frame-group parity
// (DataCount=1) from a source ALREADY BOUND to peer p, so it reaches p's FEC decoder via
// dispatchInbound's PARITY case. Offered alone, that parity reconstructs its sole data shard,
// so the decoder's Recovered counter must advance by one — the observable that a re-instantiated
// FEC decode plane is not merely present but actually recovering. It returns the decoder's
// Recovered delta.
func offerReconstructingParity(t *testing.T, m *Multipath, view *peerPathState, codec *frame.Codec, src netip.AddrPort, cfg fec.Config, seq uint64, inner string) uint64 {
	t.Helper()
	fr := view.peer.fecRecv.Load()
	if fr == nil {
		t.Fatal("offerReconstructingParity: peer has no FEC decoder armed")
	}
	before := fr.stats().Recovered
	group, index, dataCount, parityPayload := singleFrameParity(t, cfg, seq, []byte(inner))
	parity, err := codec.Encode(nil, frame.Parity{FECGroup: group, ParityIndex: index, DataCount: dataCount, PathID: view.id, Payload: parityPayload})
	if err != nil {
		t.Fatalf("encode reconstructing parity: %v", err)
	}
	m.demuxInbound(m.paths[0], parity, src)
	return fr.stats().Recovered - before
}

// TestConcentratorFECReceivePlaneLifecycle is the FEC-ENABLED T91 receive-plane acceptance
// (round-2 hardening): a configured concentrator peer's FEC DECODER is ABSENT before its first
// authenticated binding, INSTANTIATED on that binding and actually RECONSTRUCTING parity, FREED
// on teardown, and RE-INSTANTIATED as a FRESH decoder that reconstructs again after re-bind.
// Unlike the FEC-off fixtures, the 'fecRecv nil before / present after' assertions here are NOT
// vacuous: fecCfg is non-nil, so deleting ensurePeerReceiveInstantiated's fecRecv install leaves
// fecRecv nil after binding and this test red (mutation-verified).
func TestConcentratorFECReceivePlaneLifecycle(t *testing.T) {
	pskA := testKey(t, 0x11)
	pskB := testKey(t, 0x22)
	fecCfg := &fec.Config{DataShards: 4, ParityShards: 1, Deadline: testFECDeadline}
	m, _, second, clk := lazyConcentratorFEC(t, pskA, pskB, fecCfg)
	secondView := peerPathByName(second, "a")
	codecB, err := frame.NewCodec(pskB)
	if err != nil {
		t.Fatalf("build peer B codec: %v", err)
	}

	// (1) FEC decoder absent before the first authenticated binding.
	if second.fecRecv.Load() != nil {
		t.Fatal("a configured concentrator peer holds a FEC decoder before any binding (FEC receive not lazy)")
	}

	// (2) Binding instantiates the FEC decoder, and it actually reconstructs a parity-only group.
	src := synthSource(1)
	m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 1, clk), src)
	fr := second.fecRecv.Load()
	if fr == nil {
		t.Fatal("peer B's FEC decoder was not instantiated on its first authenticated binding")
	}
	if got := offerReconstructingParity(t, m, secondView, codecB, src, *fecCfg, 1000, "recovered-1"); got != 1 {
		t.Fatalf("freshly-instantiated FEC decoder recovered %d frames from a DataCount=1 parity, want 1", got)
	}

	// (3) Teardown frees the FEC decoder.
	if m.peerIsLiveLocked(second) {
		t.Fatal("peer B is unexpectedly live before any echo was fed")
	}
	if !m.TearDownPeer("peer-b") {
		t.Fatal("TearDownPeer refused to tear down a DEAD peer")
	}
	if second.fecRecv.Load() != nil {
		t.Fatal("teardown did not free peer B's FEC decoder")
	}

	// (4) Re-bind re-instantiates a FRESH decoder that reconstructs again.
	m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 2, clk), src)
	fr2 := second.fecRecv.Load()
	if fr2 == nil {
		t.Fatal("peer B's FEC decoder was not re-instantiated on re-bind")
	}
	if fr2 == fr {
		t.Fatal("re-bind reused the torn-down FEC decoder instance instead of a fresh one")
	}
	if got := offerReconstructingParity(t, m, secondView, codecB, src, *fecCfg, 2000, "recovered-2"); got != 1 {
		t.Fatalf("re-instantiated FEC decoder recovered %d frames after re-bind, want 1", got)
	}
}

// TestConcentratorFECSendPlaneReinstantiatedOnRebind is the round-2 acceptance for the PRODUCTION
// DEFECT the panel found in T91's own 're-instantiate + pass traffic on re-bind' criterion: a
// torn-down concentrator peer's FEC SEND plane (fecSend) was freed on teardown but NEVER rebuilt
// on re-bind (ensurePeerReceiveInstantiated was receive-only), so a rebound FEC-configured peer
// SENT WITHOUT PARITY until a full Close/Open. This asserts fecSend is absent → present on binding
// → freed on teardown → RE-INSTANTIATED (fresh) on re-bind, and that the rebound peer's Send
// actually EMITS PARITY again. Deleting the fecSend re-instantiation leaves this red.
func TestConcentratorFECSendPlaneReinstantiatedOnRebind(t *testing.T) {
	pskA := testKey(t, 0x11)
	pskB := testKey(t, 0x22)
	// DataShards=4: one Send batch of 4 inner datagrams closes exactly one group, emitting parity.
	fecCfg := &fec.Config{DataShards: 4, ParityShards: 1, Deadline: testFECDeadline}
	m, _, second, clk := lazyConcentratorFEC(t, pskA, pskB, fecCfg)
	secondView := peerPathByName(second, "a")

	// (1) FEC send plane absent before binding.
	if second.fecSend.Load() != nil {
		t.Fatal("a configured concentrator peer holds a FEC sender before any binding")
	}

	// (2) Binding instantiates the FEC send plane.
	src := synthSource(1)
	m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 1, clk), src)
	fs := second.fecSend.Load()
	if fs == nil {
		t.Fatal("peer B's FEC sender was not instantiated on its first authenticated binding")
	}

	// (3) Teardown frees the FEC send plane (dead peer: no echoes fed).
	if !m.TearDownPeer("peer-b") {
		t.Fatal("TearDownPeer refused to tear down a DEAD peer")
	}
	if second.fecSend.Load() != nil {
		t.Fatal("teardown did not free peer B's FEC sender")
	}

	// (4) Re-bind re-instantiates a FRESH FEC send plane — the fix for the production defect.
	m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 2, clk), src)
	fs2 := second.fecSend.Load()
	if fs2 == nil {
		t.Fatal("re-bind did not re-instantiate peer B's FEC sender: a rebound FEC peer would send WITHOUT parity")
	}
	if fs2 == fs {
		t.Fatal("re-bind reused the torn-down FEC sender instance instead of a fresh one")
	}

	// (5) The rebound peer's Send actually EMITS PARITY again. Bring its path Up and give it a
	// remote, then Send one full group's worth of inner datagrams; the encoder must close the
	// group and egress parity, counted on fecSend.parityFrames.
	raw, rawAP := rawPeer(t)
	_ = raw
	secondView.setRemote(rawAP)
	driveConcentratorPathUp(t, secondView, pskB, clk)

	batch := [][]byte{[]byte("g0-0"), []byte("g0-1"), []byte("g0-2"), []byte("g0-3")}
	if err := m.Send(batch, second.virt); err != nil {
		t.Fatalf("Send through rebound peer B: %v", err)
	}
	if got := second.fecSend.Load().parityFrames.Load(); got == 0 {
		t.Fatal("rebound FEC peer emitted NO parity frames on a full group: fecSend was not truly re-instantiated (production defect)")
	}
}

// TestDispatchInboundNilGuardsDropNotPanic is the deterministic white-box acceptance for the
// dispatchInbound nil-guards (multipath.go DATA case + PARITY case). It reproduces the exact
// TearDownPeer-vs-readLoop ordering the guards defend: bindSourceToPeer has already resolved a
// still-bound source to peer B (so demuxInbound routes straight to dispatchInbound WITHOUT
// re-checking the ring), and TearDownPeer Store(nil)s peer B's resequencer out from under the
// in-flight dispatch. The guards must DROP the frame rather than dereference the nil ring. Each
// subtest FAILS (panics on a nil-pointer dereference) when its guard is removed — the prior round's
// guard tests were vacuous because their post-teardown source was already UNBOUND, so the frame
// never reached dispatchInbound. FEC is ON so the PARITY guard (which lives inside the fecRecv!=nil
// branch) is actually exercised.
func TestDispatchInboundNilGuardsDropNotPanic(t *testing.T) {
	pskA := testKey(t, 0x11)
	pskB := testKey(t, 0x22)
	fecCfg := &fec.Config{DataShards: 4, ParityShards: 1, Deadline: testFECDeadline}

	t.Run("DATA to a bound peer whose resequencer was niled mid-flight is dropped without panic", func(t *testing.T) {
		m, primary, second, clk := lazyConcentratorFEC(t, pskA, pskB, fecCfg)
		secondView := peerPathByName(second, "a")
		dataCodecB, err := frame.NewCodec(pskB)
		if err != nil {
			t.Fatalf("build peer B data codec: %v", err)
		}
		src := synthSource(1)
		m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 1, clk), src)
		if bound, ok := m.lookupPeerBySource(src.Addr()); !ok || bound != second {
			t.Fatalf("probe did not bind source to peer B: bound=%v ok=%v", bound, ok)
		}
		// The source stays BOUND; only the ring is torn out — the ordering the DATA guard defends.
		second.resequencer.Store(nil)
		// Must not panic: with FEC armed, removing `rq == nil { return }` reaches rq.Observe on the
		// nil ring inside the fecRecv branch and panics.
		m.demuxInbound(m.paths[0], mustEncodeData(t, dataCodecB, 100, secondView.id, "raced-data"), src)
		// The frame was dropped, never misrouted into the primary.
		if it, ok := primary.resequencer.Load().Pop(); ok {
			t.Fatalf("raced DATA leaked into the primary ring (%q)", it.Payload)
		}
	})

	t.Run("PARITY to a bound peer with FEC armed but resequencer niled mid-flight is dropped without panic", func(t *testing.T) {
		m, _, second, clk := lazyConcentratorFEC(t, pskA, pskB, fecCfg)
		secondView := peerPathByName(second, "a")
		codecB, err := frame.NewCodec(pskB)
		if err != nil {
			t.Fatalf("build peer B codec: %v", err)
		}
		src := synthSource(1)
		m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 1, clk), src)
		if second.fecRecv.Load() == nil {
			t.Fatal("peer B's FEC decoder was not armed after binding")
		}
		// Nil the ring but LEAVE fecRecv armed: the PARITY guard lives inside the fecRecv!=nil
		// branch. A DataCount=1 parity reconstructs its sole shard, so removing `rq == nil { return }`
		// drives observeRecovered -> rq.ObserveRecovered on the nil ring and panics.
		second.resequencer.Store(nil)
		group, index, dataCount, parityPayload := singleFrameParity(t, *fecCfg, 55, []byte("raced-parity"))
		parity, err := codecB.Encode(nil, frame.Parity{FECGroup: group, ParityIndex: index, DataCount: dataCount, PathID: secondView.id, Payload: parityPayload})
		if err != nil {
			t.Fatalf("encode parity: %v", err)
		}
		// Must not panic: the guard drops the reconstruction rather than resequencing on a nil ring.
		m.demuxInbound(m.paths[0], parity, src)
	})
}

// TestConcentratorTeardownRebindDemuxRace drives the CONCURRENT ordering the dispatchInbound
// nil-guards and the per-peer lifecycleMu exist for: the peer's SINGLE per-path readLoop resolves
// a still-bound source and dispatches DATA/PARITY (and re-binds, re-instantiating the planes) WHILE
// TearDownPeer — driven from the device's session-event goroutine — Store(nil)s those planes. It is
// exactly one demux driver against one teardown driver, matching production's one-readLoop-per-path
// discipline (a frame.Codec is single-goroutine by design; two concurrent demuxes on one path would
// be a test artifact, not a real race). Under -race it proves (a) no data race across the atomic
// trio nor the lifecycleMu-ordered (re)instantiation-vs-teardown, and (b) no nil-dereference panic —
// the DATA case's `rq == nil` guard and the PARITY case's guard drop a frame whose ring was niled
// mid-flight rather than dereferencing it. FEC is on so BOTH dispatch guards are live.
func TestConcentratorTeardownRebindDemuxRace(t *testing.T) {
	pskA := testKey(t, 0x11)
	pskB := testKey(t, 0x22)
	fecCfg := &fec.Config{DataShards: 4, ParityShards: 1, Deadline: testFECDeadline}
	m, _, second, clk := lazyConcentratorFEC(t, pskA, pskB, fecCfg)
	secondView := peerPathByName(second, "a")
	codecB, err := frame.NewCodec(pskB)
	if err != nil {
		t.Fatalf("build peer B codec: %v", err)
	}
	dataCodecB, err := frame.NewCodec(pskB)
	if err != nil {
		t.Fatalf("build peer B data codec: %v", err)
	}
	src := synthSource(1)

	const rounds = 400
	for i := 0; i < rounds; i++ {
		// Precompute every wire serially in the test goroutine (the fake clock and the stateful
		// codecs are NOT concurrency-safe), so the demux goroutine below only touches the
		// concurrent targets under test: m.demuxInbound (a single per-path reader) and, on the
		// other goroutine, m.TearDownPeer.
		probeWire := authProbe(t, pskB, secondView.id, uint64(2*i+2), clk)
		dataWire := mustEncodeData(t, dataCodecB, uint64(1000+i), secondView.id, "d")
		group, index, dataCount, parityPayload := singleFrameParity(t, *fecCfg, uint64(5000+i), []byte("p"))
		parityWire, perr := codecB.Encode(nil, frame.Parity{FECGroup: group, ParityIndex: index, DataCount: dataCount, PathID: secondView.id, Payload: parityPayload})
		if perr != nil {
			t.Fatalf("encode parity: %v", perr)
		}

		var wg sync.WaitGroup
		wg.Add(2)
		// The one per-path reader: re-bind (ensurePeerReceiveInstantiated), then dispatch DATA and
		// PARITY through the two nil-guards, all on ONE goroutine as a real readLoop would.
		go func() {
			defer wg.Done()
			m.demuxInbound(m.paths[0], probeWire, src)
			m.demuxInbound(m.paths[0], dataWire, src)
			m.demuxInbound(m.paths[0], parityWire, src)
		}()
		// The session-event driver: teardown — Store(nil)s the heavy trio under m.mu+lifecycleMu,
		// racing the reader's dispatch and re-instantiation.
		go func() {
			defer wg.Done()
			m.TearDownPeer("peer-b")
		}()
		wg.Wait()
	}

	// Positive postcondition: after all the churn the peer still re-binds cleanly and carries
	// DATA — the guards drop raced frames, they do not wedge the datapath.
	m.TearDownPeer("peer-b") // ensure a known torn-down starting point (no-op if already down)
	m.demuxInbound(m.paths[0], authProbe(t, pskB, secondView.id, 999999, clk), src)
	if second.resequencer.Load() == nil {
		t.Fatal("peer B did not re-instantiate its ring after the concurrent churn")
	}
	m.demuxInbound(m.paths[0], mustEncodeData(t, dataCodecB, 888888, secondView.id, "final"), src)
	if it, ok := second.resequencer.Load().Pop(); !ok || !bytes.Equal(it.Payload, []byte("final")) {
		t.Fatalf("peer B did not carry DATA after the concurrent churn: ok=%v payload=%q", ok, it.Payload)
	}
}

package bind

import (
	"encoding/binary"
	"fmt"
	"sync"
	"sync/atomic"
	"time"

	"github.com/7mind/wanbond/internal/adaptivefec"
	"github.com/7mind/wanbond/internal/fec"
	"github.com/7mind/wanbond/internal/telemetry"
)

// FEC datapath integration (T24).
//
// The fixed-ratio Reed-Solomon engine (internal/fec) is wired into the multipath
// datapath as a SEND-side encoder and a RECEIVE-side decoder that composes with the
// T18 resequencer, T21 weighted scheduling, and T30 dynamic paths without regressing
// any of them. FEC is OFF unless a config carries an [fec] block (NewMultipath's
// fecCfg is nil otherwise), in which case the datapath is byte-for-byte the pre-T24
// behaviour.
//
// Wire mapping. The FEC data-shard bytes are OuterSeq || inner: the encoder codes
// parity over that, but the 8-byte outer-seq prefix is NOT transmitted — the DATA
// frame carries the outer-seq in its header and the inner datagram in its payload,
// and both sender and receiver reconstitute the shard bytes as
// header-seq || frame-payload. This keeps a recovered shard SELF-DESCRIBING (its
// reconstructed bytes carry its own outer-seq, so a frame reconstructed from parity
// resequences at its ORIGINAL outer-seq even when EVERY data frame of the group was
// lost) while adding only one wire byte per DATA frame (the shard index in the DATA
// header) and the group cardinality M per PARITY frame. See internal/frame.
//
// Concurrency. The encoder rides the Send path, already serialized under m.mu, plus
// a single deadline-tick goroutine that TryLocks m.mu (never blocking, so it can
// never deadlock Close's readersWG.Wait held under m.mu — the tickLivenessFromReceive
// discipline). The decoder is fed from the per-path readLoop goroutines (many
// concurrent), so it is guarded by its own mutex, disjoint from m.mu and from the
// resequencer's — matching the resequencer's lock discipline (never held across a
// syscall). Recovered frames are handed to the resequencer exactly like a
// natively-received frame, so FEC recovery slots in strictly BEFORE resequencing.

// fecSeqPrefixLen is the width of the big-endian outer-seq prefix that heads each
// FEC data-shard's coded bytes. It is reconstructed from the DATA frame header on
// both ends and never travels the wire (see the wire mapping above).
const fecSeqPrefixLen = 8

// maxFECDeadline is the authoritative upper bound on the FEC group-close deadline,
// coupling it to the receive resequencer's per-gap timeout (T24, defect #4). A group
// flushed by the deadline emits its parity `deadline` after the group opened; the
// reconstructed frames must reach the resequencer BEFORE it skips the gap
// (resequencerTimeout after the gap forms), or recovery is structurally too late — the
// gap is skipped first and the recovered frame dropped as past the release point. Held
// at half the resequencer timeout, the deadline leaves the other half for propagation
// and reconstruction. config validation enforces a matching load-time bound; this is
// the authoritative guard for any fec.Config built directly.
const maxFECDeadline = resequencerTimeout / 2

// fecRetainGroups bounds the decoder's retained-group window (SetRetainWindow): a
// group more than this many group-ids behind the newest offered group is evicted,
// which is also when an incomplete group is finally accounted unrecoverable. It is
// sized well above the reorder/loss span a single group can straddle so a group is
// never evicted while its own shards are still legitimately in flight, yet small
// enough that an unrecoverable group is accounted promptly rather than after a
// 4096-group default. A group spans a handful of outer-seqs, so this comfortably
// exceeds the resequencerWindow's reordering budget in group units.
const fecRetainGroups = 512

// fecResidualLossWindow is the trailing outer-seq width of the receive-side residual-
// loss estimator (T29): the post-FEC-recovery loss the P4 acceptance bounds. It is
// deliberately WIDER than the telemetry default (512) for two reasons: (1) resolution —
// the P4 bound is 0.5%, so the window must resolve finer than 1/512≈0.2%; 8192 gives
// ~0.012% granularity, well under the bound; (2) stability — averaging the residual over
// ~thousands of groups smooths the per-group binomial variance into a steady-state figure.
// It stays far below the resequencer window's reordering budget, and is wide enough that a
// recovered frame arriving a group or two after its gap still retroactively fills it, so
// genuinely-unrecovered seqs (whole-group and beyond-budget losses) are the only residual.
const fecResidualLossWindow = 8192

// adaptiveControlInterval throttles how often the FEC tick loop folds a fresh loss
// sample into the adaptive controller (T29). It matches the probe cadence — the rate at
// which per-path loss estimates actually refresh — so the controller's EWMA sees ~one
// sample per probe interval as its tuning (internal/adaptivefec) assumes, regardless of
// the (possibly much smaller) FEC group-close deadline the tick loop runs at.
const adaptiveControlInterval = telemetry.DefaultProbeInterval

// fecSender is the send-side FEC state: the group-forming encoder (accessed only
// under the Bind's m.mu, on the Send path and the deadline-tick goroutine) plus the
// parity-overhead counters the /metrics exposition reports. The counters are
// atomics read lock-free at snapshot time, mirroring the T23 per-path byte counters.
type fecSender struct {
	enc *fec.Encoder

	// ctrl is the adaptive-FEC controller (T29), nil in fixed-ratio mode. It is driven
	// (Observe) and read (Parity) ONLY from under the Bind's m.mu — the FEC tick loop's
	// throttled drive and, transitively, the Send path — so it needs no lock of its own,
	// matching the encoder's single-writer discipline. lastControlTick/haveControlTick
	// throttle the drive to adaptiveControlInterval and are likewise m.mu-guarded.
	ctrl            *adaptivefec.Controller
	lastControlTick time.Time
	haveControlTick bool

	dataFrames   atomic.Uint64
	dataBytes    atomic.Uint64
	parityFrames atomic.Uint64
	parityBytes  atomic.Uint64
}

// fecReceiver is the receive-side FEC state: the recovery decoder guarded by its own
// mutex (the per-path readLoop goroutines feed it concurrently). deliveredRecovered is
// the HONEST recovery count for /metrics — data frames a reconstruction actually
// delivered to the resequencer AHEAD of its release point (not merely reconstructed:
// a frame rebuilt after the resequencer already skipped its gap is dropped as late and
// must not be counted, else /metrics overstates recovery). It is an atomic so the
// snapshot reads it lock-free.
type fecReceiver struct {
	mu  sync.Mutex
	dec *fec.Decoder

	deliveredRecovered atomic.Uint64

	// connLoss is the POST-FEC-RECOVERY residual-loss estimator (T29, the P4 signal):
	// every natively-received DATA outer-seq AND every FEC-reconstructed outer-seq is
	// Observed into it, so its Loss() fraction is exactly the connection-scoped loss that
	// survived FEC — outer-seqs neither received nor recovered. It is internally
	// synchronized (its own mutex), fed concurrently by the per-path readLoop goroutines
	// exactly like the resequencer, and read lock-free-enough at scrape time.
	connLoss *telemetry.ConnLoss
}

// offer feeds one surviving shard into the decoder and returns any data payloads it
// reconstructed (never-received frames). It holds the decoder mutex only for the
// in-memory reconstruct — never across a syscall — so it never blocks the send path.
func (r *fecReceiver) offer(s fec.Shard) ([]fec.Recovered, error) {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.dec.Offer(s)
}

// stats snapshots the decoder's cumulative recovery counters under its mutex.
func (r *fecReceiver) stats() fec.DecoderStats {
	r.mu.Lock()
	defer r.mu.Unlock()
	return r.dec.Stats()
}

// FECStats is a consistent snapshot of the Bind's FEC counters (T24), the shape the
// metrics.Source adapter maps onto the connection-scoped /metrics FEC series.
// DataFrames is the send-side DATA-frame count (the fixed-ratio overhead's
// denominator); ParityFrames/ParityBytes are the send-side overhead (parity emitted);
// Recovered and Unrecoverable are the receive-side outcome (data shards reconstructed
// from parity, and data shards lost beyond repair capacity). FEC being
// connection-scoped, these carry no path label. The frame overhead the operator cares
// about is ParityFrames/DataFrames, which tends to ParityShards/DataShards (M/K) once
// groups fill; both are counted only for frames that actually reached the socket, so
// the ratio reflects wire cost actually spent.
type FECStats struct {
	DataFrames    uint64
	DataBytes     uint64
	ParityFrames  uint64
	ParityBytes   uint64
	Recovered     uint64
	Unrecoverable uint64
	// ResidualLoss is the current post-FEC-recovery connection loss fraction in [0,1]
	// (T29): the share of outer-seqs neither natively received nor reconstructed from
	// parity. It is the P4 acceptance signal — the loss FEC did not mask. Zero when FEC is
	// disabled or no data has flowed.
	ResidualLoss float64
}

// fecShardPayload builds the FEC data-shard coded bytes for outer-seq seq over the
// opaque inner datagram: seq (8 BE) || inner. The sender codes parity over this; the
// receiver reconstitutes the identical bytes from the DATA frame header + payload so
// the decoder's shards match what the encoder coded.
func fecShardPayload(seq uint64, inner []byte) []byte {
	b := make([]byte, fecSeqPrefixLen+len(inner))
	binary.BigEndian.PutUint64(b, seq)
	copy(b[fecSeqPrefixLen:], inner)
	return b
}

// splitFECShardPayload inverts fecShardPayload, returning the outer-seq and a fresh
// copy of the inner datagram. It fails fast on a shard too short to hold the prefix,
// which would indicate a decoder/encoder mismatch rather than a recoverable
// condition. The inner copy lets the resequencer take ownership without retaining the
// larger coded-shard backing array.
func splitFECShardPayload(b []byte) (uint64, []byte, error) {
	if len(b) < fecSeqPrefixLen {
		return 0, nil, fmt.Errorf("bind: recovered FEC shard %d bytes, shorter than the %d-byte outer-seq prefix", len(b), fecSeqPrefixLen)
	}
	seq := binary.BigEndian.Uint64(b[:fecSeqPrefixLen])
	inner := make([]byte, len(b)-fecSeqPrefixLen)
	copy(inner, b[fecSeqPrefixLen:])
	return seq, inner, nil
}

//   - PROBE, IsEcho=false: an authenticated peer probe. Its source is learned as
//     the path's remote (D11: a probe-only backup path gets a usable return remote
//     before any DATA flows) and it is reflected straight back to that source via
//     this path's socket (T13 Reflector). Reflection writes independently of the
//     scheduler/getRemote so an echo returns even on a not-yet-active path.
//   - PROBE, IsEcho=true: an authenticated echo of one of our own probes. Its
//     source is learned as the remote too, and the raw echo is fed into this
//     path's Prober (HandleEcho) to update RTT/loss and drive liveness.
//   - anything else (PARITY/CONTROL/malformed): dropped.
//
// Remote-learning and reflection touch only authenticated (MAC-verified) PROBE
// frames — Decode has already verified the tag for the PROBE kind — which is what
// resolves D9: an attacker who forges an unauthenticated DATA frame can no longer
// repoint a path's return endpoint.
//
// FEC seam (T24): DATA ingestion via resequencer.Observe is keyed purely on
// outer-seq, so an FEC decoder can slot in BEFORE the resequencer with no change
// here — PARITY (dropped today) will feed the decoder, which reconstructs missing
// DATA frames and calls Observe with their ORIGINAL outer-seq, identical to a
// natively-received frame.
func (m *Multipath) handleInbound(ps *peerPathState, raw []byte, srcAP netip.AddrPort) {
	fr, err := ps.codec.Decode(raw)
	if err != nil {
		return // drop malformed / PSK-mismatched outer frames
	}
	m.dispatchInbound(ps, fr, raw, srcAP)
}

// demuxInbound is the readLoop's per-frame entry on a (possibly shared) socket: it resolves
// which bound peer's view owns the datagram, then hands the frame to handleInbound on THAT
